import{_ as d,o as a,c as e,a6 as r}from"./chunks/framework.wLlb4ebq.js";const m=JSON.parse('{"title":"Linux.do Adapter","description":"","frontmatter":{},"headers":[],"relativePath":"integrations/linuxdo.md","filePath":"integrations/linuxdo.md"}'),i={name:"integrations/linuxdo.md"};function o(n,t,l,h,s,c){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="linux-do-adapter" tabindex="-1">Linux.do Adapter <a class="header-anchor" href="#linux-do-adapter" aria-label="Permalink to “Linux.do Adapter”">​</a></h1><p>Linux.do adapter 负责读取收藏列表和帖子详情，并把 Discourse 风格内容转换为 LD-Notion 的 normalized schema mapping。</p><h2 id="extraction-rules" tabindex="-1">Extraction rules <a class="header-anchor" href="#extraction-rules" aria-label="Permalink to “Extraction rules”">​</a></h2><table tabindex="0"><thead><tr><th>Rule</th><th>Description</th></tr></thead><tbody><tr><td>收藏列表</td><td>从已登录用户可见的收藏入口加载 topic 列表</td></tr><tr><td>帖子详情</td><td>拉取 topic 内容、楼层、作者、回复和统计信息</td></tr><tr><td>筛选</td><td>支持仅主楼、仅楼主、楼层范围、包含 / 排除关键词</td></tr><tr><td>格式转换</td><td>将标题、段落、列表、引用、代码块、表格、图片转换为 Notion Blocks</td></tr><tr><td>图片策略</td><td>上传到 Notion、外链引用或跳过</td></tr></tbody></table><h2 id="metadata-fields" tabindex="-1">Metadata fields <a class="header-anchor" href="#metadata-fields" aria-label="Permalink to “Metadata fields”">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Meaning</th></tr></thead><tbody><tr><td>title</td><td>帖子标题</td></tr><tr><td>url</td><td>原帖链接</td></tr><tr><td>author</td><td>楼主或楼层作者</td></tr><tr><td>collectedAt</td><td>收藏时间</td></tr><tr><td>replyCount</td><td>回复数量</td></tr><tr><td>viewCount</td><td>浏览数</td></tr><tr><td>likeCount</td><td>点赞数</td></tr><tr><td>tags/category</td><td>AI 或规则生成的分类标签</td></tr></tbody></table><h2 id="normalized-schema-mapping" tabindex="-1">normalized schema mapping <a class="header-anchor" href="#normalized-schema-mapping" aria-label="Permalink to “normalized schema mapping”">​</a></h2><table tabindex="0"><thead><tr><th>Source field</th><th>normalizedContent field</th><th>Destination</th></tr></thead><tbody><tr><td>topic id / URL</td><td>identity.sourceId / identity.url</td><td>链接</td></tr><tr><td>topic title</td><td>content.title</td><td>标题</td></tr><tr><td>cooked HTML / posts</td><td>content.body</td><td>Notion children blocks</td></tr><tr><td>author username</td><td>metadata.author</td><td>作者</td></tr><tr><td>stats</td><td>metadata.extra</td><td>帖子数 / 浏览数 / 点赞数</td></tr><tr><td>selected filters</td><td>routing.template</td><td>导出配置说明</td></tr></tbody></table><h2 id="fallback-behavior" tabindex="-1">Fallback behavior <a class="header-anchor" href="#fallback-behavior" aria-label="Permalink to “Fallback behavior”">​</a></h2><table tabindex="0"><thead><tr><th>Failure</th><th>fallback behavior</th></tr></thead><tbody><tr><td>收藏列表加载失败</td><td>提示登录状态或网络问题</td></tr><tr><td>部分帖子详情失败</td><td>跳过失败项并在报告中列出</td></tr><tr><td>图片上传失败</td><td>尝试文件上传或改用外链 / 跳过策略</td></tr><tr><td>Notion 429</td><td>等待后重试</td></tr><tr><td>格式不支持</td><td>降级为段落文本</td></tr></tbody></table><h2 id="known-limitations" tabindex="-1">Known limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to “Known limitations”">​</a></h2><ul><li>自动导入依赖页面保持打开。</li><li>需要用户当前浏览器已登录 Linux.do。</li><li>私有或权限受限图片可能无法被 Notion 访问。</li><li>复杂 HTML 结构可能无法 100% 映射到 Notion Blocks。</li></ul>',12)])])}const p=d(i,[["render",o]]);export{m as __pageData,p as default};
